import { englishKeyboardLayout, englishFingerMap, englishFingerNames } from './keyboards/english';
import { punjabiKeyboardLayout, punjabiFingerMap, punjabiFingerNames } from './keyboards/punjabi';

/**
 * Get keyboard configuration for a specific language
 * @param {string} languageId - Language identifier (english, punjabi, etc.)
 * @returns {Object} Keyboard configuration with layout, fingerMap, and fingerNames
 */
export const getKeyboardConfig = (languageId) => {
  const keyboards = {
    english: {
      layout: englishKeyboardLayout,
      fingerMap: englishFingerMap,
      fingerNames: englishFingerNames
    },
    punjabi: {
      layout: punjabiKeyboardLayout,
      fingerMap: punjabiFingerMap,
      fingerNames: punjabiFingerNames
    }
  };

  return keyboards[languageId] || keyboards.english;
};

/**
 * Get keyboard layout only
 */
export const getKeyboardLayout = (languageId) => {
  return getKeyboardConfig(languageId).layout;
};

/**
 * Get finger mapping only
 */
export const getFingerMap = (languageId) => {
  return getKeyboardConfig(languageId).fingerMap;
};

/**
 * Get finger names only
 */
export const getFingerNames = (languageId) => {
  return getKeyboardConfig(languageId).fingerNames;
};
